+let eventCounter = 0;
+
+export function createEvent<T>(
+  type: EventType,
+  source: AgentId | 'swarm',
+  payload: T
+): SwarmEvent<T> {
+  return {
+    id: `evt-${Date.now()}-${++eventCounter}`,
+    type,
+    timestamp: Date.now(),
+    source,
+    payload
+  };
+}

